packages/core/src/acp/acp-transcript-parser/fixtures/claude-acp-transcript.json:1703:                  "content": "/**\n * Pure ACP session state machine.\n *\n * Separates inputs into two distinct kinds:\n *\n * - Commands — intents from the public API that MAY be rejected by validation.\n *   They produce zero or more DomainEvents on success, or an AcpRuntimeError on\n *   failure. No state changes occur on rejection.\n *\n * - DomainEvents — facts from the agent process, ACP notifications, or our own\n *   orchestration that are ALWAYS folded into state. An out-of-place event\n *   yields only a diagnostic `warn` Effect, never an error.\n *\n * The two pure functions `decide` and `evolve` contain no I/O. The runtime\n * feeds commands through `decide` to get events, then feeds events through\n * `evolve` to get the next state and the list of Effects to perform.\n *\n * State machine transitions:\n *\n *   starting → replaying (E: ReplayStarted — only when loadSession capable)\n *   starting → ready     (E: SessionReady — newSession path)\n *   replaying → ready    (E: ReplayEnded)\n *   ready → working      (C: Prompt → E: PromptStarted)\n *   working → ready      (E: TurnEnded)\n *   working → cancelling (C: Cancel → E: CancellationRequested)\n *   cancelling → ready   (E: TurnEnded)\n *   {ready,working,cancelling} → closed (E: ProcessClosed)\n */\n\nimport type {\n  AvailableCommand,\n  SessionConfigOption,\n  SessionModeState,\n  StopReason,\n} from '@agentclientprotocol/sdk';\nimport type { Result } from '@emdash/shared';\nimport { ok } from '@emdash/shared';\nimport type { AgentUpdate } from './agent-update';\nimport type { AcpRuntimeError } from './errors';\nimport { acpErr } from './errors';\nimport type { AcpPermissionRequest } from './permissions';\nimport type {\n  AcpTurn,\n  ChatHistory,\n  SessionSnapshot,\n  SessionState,\n  SessionUsage,\n  TurnSource,\n  TurnStatus,\n} from './state';\n\n// Re-export the snapshot mirror primitives so renderer-safe consumers can import\n// them from this node-free entry instead of the full `@emdash/core/acp` barrel.\nexport { toSessionSnapshot, type SessionSnapshot } from './state';\n\n// ---------------------------------------------------------------------------\n// Phase (discriminated union carrying the active turn in-line)\n// ---------------------------------------------------------------------------\n\nexport type SessionPhase =\n  | { kind: 'starting' }\n  | { kind: 'replaying'; turn: AcpTurn }\n  | { kind: 'ready' }\n  | { kind: 'working'; turn: AcpTurn }\n  | { kind: 'cancelling'; turn: AcpTurn }\n  | { kind: 'closed'; exitCode: number | null };\n\n/** Derives the `SessionLifecycle` string from a phase. */\nexport function phaseToLifecycle(phase: SessionPhase): SessionLifecycle {\n  return phase.kind;\n}\n\n/** The active turn if the phase carries one, otherwise null. */\nexport function activeTurnFromPhase(phase: SessionPhase): AcpTurn | null {\n  if (phase.kind === 'replaying' || phase.kind === 'working' || phase.kind === 'cancelling') {\n    return phase.turn;\n  }\n  return null;\n}\n\n// Re-export for consumers that only care about the lifecycle string\nexport type SessionLifecycle =\n  | 'starting'\n  | 'replaying'\n  | 'ready'\n  | 'working'\n  | 'cancelling'\n  | 'closed';\n\n// ---------------------------------------------------------------------------\n// Machine state\n// ---------------------------------------------------------------------------\n\nexport interface SessionMachineState {\n  readonly conversationId: string;\n  readonly phase: SessionPhase;\n  readonly committedTurns: readonly AcpTurn[];\n  readonly pendingPermissions: readonly AcpPermissionRequest[];\n  /**\n   * Agent-advertised session modes. Null until the first newSession or\n   * loadSession response arrives, or if the agent doesn't support modes.\n   */\n  readonly modes: SessionModeState | null;\n  /**\n   * Full set of session config options as reported by the agent. The model\n   * selector is one of these (category === 'model'). Authoritative — updated\n   * from newSession/loadSession responses, setSessionConfigOption responses,\n   * and config_option_update notifications.\n   */\n  readonly configOptions: readonly SessionConfigOption[];\n  /** Slash commands the agent currently supports. */\n  readonly availableCommands: readonly AvailableCommand[];\n  /**\n   * The stop reason from the last completed turn. Null on first start or\n   * if no turn has completed yet. Drives the composer's notice band.\n   */\n  readonly lastStopReason: StopReason | null;\n  /** Latest context-window and cost figures from usage_update, null until the first notification. */\n  readonly usage: SessionUsage | null;\n  /** Monotonic sequence counter — shared across all turns of a conversation. */\n  readonly nextSeq: number;\n  /** Counter used to generate unique, stable turn ids. */\n  readonly nextTurnIndex: number;\n}\n\nexport function initialMachineState(conversationId: string): SessionMachineState {\n  return {\n    conversationId,\n    phase: { kind: 'starting' },\n    committedTurns: [],\n    pendingPermissions: [],\n    modes: null,\n    configOptions: [],\n    availableCommands: [],\n    lastStopReason: null,\n    usage: null,\n    nextSeq: 0,\n    nextTurnIndex: 0,\n  };\n}\n\n// ---------------------------------------------------------------------------\n// Commands (validated intents — may be rejected)\n// ---------------------------------------------------------------------------\n\nexport type Command =\n  /** Send a user message to the agent. Only valid when phase === 'ready'. */\n  | { type: 'Prompt'; userUpdate: AgentUpdate }\n  /** Cancel the in-flight turn. Only valid when phase === 'working'. Idempotent elsewhere. */\n  | { type: 'Cancel' }\n  /**\n   * Resolve a pending permission request. Only valid when the requestId is\n   * present in pendingPermissions.\n   */\n  | { type: 'ResolvePermission'; requestId: string; optionId: string | null }\n  /** Switch the active session mode. Only valid when modes is non-null and modeId is available. */\n  | { type: 'SetMode'; modeId: string }\n  /**\n   * Change the active model (or any other config option by id). The runtime\n   * sends this as setSessionConfigOption; the response is authoritative.\n   */\n  | { type: 'SetConfigOption'; configId: string; value: string };\n\n// ---------------------------------------------------------------------------\n// Domain events (facts — always folded)\n// ---------------------------------------------------------------------------\n\nexport type DomainEvent =\n  /** Session established via loadSession — replay turn begins. */\n  | { type: 'ReplayStarted' }\n  /** Replay turn finished. */\n  | { type: 'ReplayEnded'; status: Exclude<TurnStatus, 'active'> }\n  /** Session established via newSession — immediately ready. */\n  | {\n      type: 'SessionReady';\n      modes?: SessionModeState | null;\n      configOptions?: readonly SessionConfigOption[] | null;\n    }\n  /** Session loaded via loadSession — session is ready after replay. Carries session metadata. */\n  | {\n      type: 'SessionLoaded';\n      modes?: SessionModeState | null;\n      configOptions?: readonly SessionConfigOption[] | null;\n    }\n  /** A new live turn begins, opening the working phase. */\n  | { type: 'PromptStarted'; userUpdate: AgentUpdate }\n  /** A turn-level update arrived from the agent. */\n  | { type: 'Updated'; update: AgentUpdate }\n  /** The active turn ended. */\n  | { type: 'TurnEnded'; outcome: TurnOutcome }\n  /** User initiated cancellation — transition to cancelling. */\n  | { type: 'CancellationRequested' }\n  /** Agent requested user permission for a tool call. */\n  | { type: 'PermissionRequested'; request: AcpPermissionRequest }\n  /** A pending permission was resolved (by user or by drain). */\n  | { type: 'PermissionResolved'; requestId: string }\n  /** Session-scoped metadata changed (modes / configOptions / availableCommands / usage). */\n  | {\n      type: 'MetaChanged';\n      modes?: SessionModeState | null;\n      configOptions?: readonly SessionConfigOption[] | null;\n      availableCommands?: readonly AvailableCommand[] | null;\n      usage?: SessionUsage | null;\n    }\n  /** The agent process exited or the connection closed. */\n  | { type: 'ProcessClosed'; exitCode: number | null };\n\nexport type TurnOutcome = { kind: 'stopped'; stopReason: StopReason } | { kind: 'errored' };\n\n// ---------------------------------------------------------------------------\n// Effects (outputs that the runtime interprets — no I/O inside the machine)\n// ---------------------------------------------------------------------------\n\nexport type Effect =\n  /** Emit the current lifecycle + activeTurnId to the listener. */\n  | { type: 'state' }\n  /** Emit a turn update to the listener. */\n  | { type: 'update'; turnId: string; seq: number; update: AgentUpdate }\n  /** Commit the turn to history and notify the listener. */\n  | { type: 'turnCommitted'; turn: AcpTurn }\n  /** Notify the listener of a new permission request. */\n  | { type: 'permissionRequest'; request: AcpPermissionRequest }\n  /**\n   * Notify the listener that a permission was resolved. Also answers the\n   * non-serializable resolver callback held by the runtime.\n   */\n  | { type: 'permissionResolved'; requestId: string; cancelled: boolean }\n  /** Notify the listener that session-scoped metadata changed. */\n  | { type: 'meta' }\n  /** Notify the listener that the session closed. */\n  | { type: 'closed'; exitCode: number | null }\n  /** Emit start/stop/error agent lifecycle events. */\n  | { type: 'agentEvent'; phase: 'start' | 'stop' | 'error' }\n  /** Log a diagnostic warning for unexpected but non-fatal situations. */\n  | { type: 'warn'; message: string };\n\n// ---------------------------------------------------------------------------\n// decide — pure validation, no state change\n// ---------------------------------------------------------------------------\n\n/**\n * Validates a command against the current state. Returns the list of\n * DomainEvents to fold if valid, or an AcpRuntimeError if not.\n */\nexport function decide(\n  s: SessionMachineState,\n  cmd: Command\n): Result<DomainEvent[], AcpRuntimeError> {\n  switch (cmd.type) {\n    case 'Prompt': {\n      if (!isPromptReady(phaseToLifecycle(s.phase))) {\n        return acpErr.invalidState(`Cannot send a prompt while session is '${s.phase.kind}'`);\n      }\n      return ok([{ type: 'PromptStarted', userUpdate: cmd.userUpdate }]);\n    }\n\n    case 'Cancel': {\n      if (s.phase.kind !== 'working') {\n        // Idempotent — cancelling or already ready/closed is fine\n        return ok([]);\n      }\n      return ok([{ type: 'CancellationRequested' }]);\n    }\n\n    case 'ResolvePermission': {\n      const found = s.pendingPermissions.some((p) => p.requestId === cmd.requestId);\n      if (!found) {\n        return acpErr.invalidState(`No pending permission request with id '${cmd.requestId}'`);\n      }\n      return ok([{ type: 'PermissionResolved', requestId: cmd.requestId }]);\n    }\n\n    case 'SetMode': {\n      if (!s.modes) {\n        return acpErr.invalidState('Agent does not support session modes');\n      }\n      const available = s.modes.availableModes.some((m) => m.id === cmd.modeId);\n      if (!available) {\n        return acpErr.setModeFailed({\n          name: 'Error',\n          message: `Mode '${cmd.modeId}' is not in the available modes list`,\n        });\n      }\n      // The actual RPC call happens in the runtime; the machine only validates.\n      // The MetaChanged event arrives after the RPC response and is the truth.\n      return ok([]);\n    }\n\n    case 'SetConfigOption': {\n      // Validation: option must exist. The runtime sends the RPC and then\n      // applies the returned configOptions via a MetaChanged event.\n      const exists = s.configOptions.some((o) => o.id === cmd.configId);\n      if (!exists) {\n        return acpErr.setConfigFailed({\n          name: 'Error',\n          message: `Config option '${cmd.configId}' is not known`,\n        });\n      }\n      return ok([]);\n    }\n  }\n}\n\n// ---------------------------------------------------------------------------\n// evolve — pure fold, no side effects\n// ---------------------------------------------------------------------------\n\n/**\n * Folds a DomainEvent into a new state, returning the updated state and the\n * list of Effects that the runtime must perform (I/O, listener calls, etc.).\n * An out-of-place event yields only a `warn` Effect and leaves state unchanged.\n */\nexport function evolve(\n  s: SessionMachineState,\n  ev: DomainEvent\n): { state: SessionMachineState; effects: Effect[] } {\n  switch (ev.type) {\n    case 'ReplayStarted': {\n      if (s.phase.kind !== 'starting') {\n        return warn(s, `ReplayStarted in phase '${s.phase.kind}'`);\n      }\n      const turn = makeTurn(s, 'replay');\n      return {\n        state: {\n          ...s,\n          phase: { kind: 'replaying', turn },\n          nextTurnIndex: s.nextTurnIndex + 1,\n        },\n        effects: [{ type: 'state' }],\n      };\n    }\n\n    case 'ReplayEnded': {\n      if (s.phase.kind !== 'replaying') {\n        return warn(s, `ReplayEnded in phase '${s.phase.kind}'`);\n      }\n      const turn = s.phase.turn;\n      const committed: AcpTurn = {\n        ...turn,\n        status: ev.status,\n        endSeq: s.nextSeq,\n        stopReason: null,\n      };\n      return {\n        state: {\n          ...s,\n          phase: { kind: 'ready' },\n          committedTurns: [...s.committedTurns, committed],\n        },\n        effects: [{ type: 'turnCommitted', turn: committed }, { type: 'state' }],\n      };\n    }\n\n    case 'SessionReady': {\n      if (s.phase.kind !== 'starting') {\n        return warn(s, `SessionReady in phase '${s.phase.kind}'`);\n      }\n      return {\n        state: {\n          ...s,\n          phase: { kind: 'ready' },\n          modes: ev.modes ?? s.modes,\n          configOptions: ev.configOptions ?? s.configOptions,\n        },\n        effects: [\n          { type: 'state' },\n          ...(needsMetaEffect(s, ev) ? ([{ type: 'meta' }] as Effect[]) : []),\n        ],\n      };\n    }\n\n    case 'SessionLoaded': {\n      if (s.phase.kind !== 'replaying') {\n        return warn(s, `SessionLoaded in phase '${s.phase.kind}'`);\n      }\n      return {\n        state: {\n          ...s,\n          modes: ev.modes ?? s.modes,\n          configOptions: ev.configOptions ?? s.configOptions,\n        },\n        effects: needsMetaEffect(s, ev) ? [{ type: 'meta' }] : [],\n      };\n    }\n\n    case 'PromptStarted': {\n      if (s.phase.kind !== 'ready') {\n        return warn(s, `PromptStarted in phase '${s.phase.kind}'`);\n      }\n      const turn = makeTurn(s, 'live');\n      const seq = s.nextSeq;\n      // Record the synthesized user message as the leading update\n      const turnWithUser: AcpTurn = {\n        ...turn,\n        updates: [{ seq, update: ev.userUpdate }],\n      };\n      return {\n        state: {\n          ...s,\n          phase: { kind: 'working', turn: turnWithUser },\n          nextSeq: seq + 1,\n          nextTurnIndex: s.nextTurnIndex + 1,\n        },\n        effects: [\n          { type: 'state' },\n          { type: 'update', turnId: turn.id, seq, update: ev.userUpdate },\n          { type: 'agentEvent', phase: 'start' },\n        ],\n      };\n    }\n\n    case 'Updated': {\n      const active = activeTurnFromPhase(s.phase);\n      if (!active) {\n        return warn(s, `Updated with no active turn (phase: '${s.phase.kind}')`);\n      }\n      const seq = s.nextSeq;\n      const updatedTurn: AcpTurn = {\n        ...active,\n        updates: [...active.updates, { seq, update: ev.update }],\n      };\n      return {\n        state: {\n          ...s,\n          phase: replaceTurnInPhase(s.phase, updatedTurn),\n          nextSeq: seq + 1,\n        },\n        effects: [{ type: 'update', turnId: active.id, seq, update: ev.update }],\n        // NB: lifecycle deliberately unchanged — Updated never flips to 'working'\n      };\n    }\n\n    case 'TurnEnded': {\n      const active = activeTurnFromPhase(s.phase);\n      if (!active) {\n        return warn(s, `TurnEnded with no active turn (phase: '${s.phase.kind}')`);\n      }\n      const stopReason = ev.outcome.kind === 'stopped' ? ev.outcome.stopReason : null;\n      const status: Exclude<TurnStatus, 'active'> =\n        ev.outcome.kind === 'errored'\n          ? 'error'\n          : stopReason === 'cancelled'\n            ? 'cancelled'\n            : 'complete';\n      const committed: AcpTurn = {\n        ...active,\n        status,\n        endSeq: s.nextSeq,\n        stopReason,\n      };\n      return {\n        state: {\n          ...s,\n          phase: { kind: 'ready' },\n          committedTurns: [...s.committedTurns, committed],\n          lastStopReason: stopReason,\n        },\n        effects: [\n          { type: 'turnCommitted', turn: committed },\n          { type: 'state' },\n          { type: 'agentEvent', phase: ev.outcome.kind === 'errored' ? 'error' : 'stop' },\n        ],\n      };\n    }\n\n    case 'CancellationRequested': {\n      if (s.phase.kind !== 'working') {\n        return warn(s, `CancellationRequested in phase '${s.phase.kind}'`);\n      }\n      // Drain all pending permissions with cancelled=true\n      const drainEffects: Effect[] = s.pendingPermissions.map((p) => ({\n        type: 'permissionResolved' as const,\n        requestId: p.requestId,\n        cancelled: true,\n      }));\n      return {\n        state: {\n          ...s,\n          phase: { kind: 'cancelling', turn: s.phase.turn },\n          pendingPermissions: [],\n        },\n        effects: [...drainEffects, { type: 'state' }],\n      };\n    }\n\n    case 'PermissionRequested': {\n      return {\n        state: {\n          ...s,\n          pendingPermissions: [...s.pendingPermissions, ev.request],\n        },\n        effects: [{ type: 'permissionRequest', request: ev.request }],\n      };\n    }\n\n    case 'PermissionResolved': {\n      return {\n        state: {\n          ...s,\n          pendingPermissions: s.pendingPermissions.filter((p) => p.requestId !== ev.requestId),\n        },\n        effects: [{ type: 'permissionResolved', requestId: ev.requestId, cancelled: false }],\n      };\n    }\n\n    case 'MetaChanged': {\n      return {\n        state: {\n          ...s,\n          modes: ev.modes !== undefined ? (ev.modes ?? s.modes) : s.modes,\n          configOptions:\n            ev.configOptions !== undefined\n              ? (ev.configOptions ?? s.configOptions)\n              : s.configOptions,\n          availableCommands:\n            ev.availableCommands !== undefined\n              ? (ev.availableCommands ?? s.availableCommands)\n              : s.availableCommands,\n          usage: ev.usage !== undefined ? (ev.usage ?? s.usage) : s.usage,\n        },\n        effects: [{ type: 'meta' }],\n      };\n    }\n\n    case 'ProcessClosed': {\n      const drainEffects: Effect[] = s.pendingPermissions.map((p) => ({\n        type: 'permissionResolved' as const,\n        requestId: p.requestId,\n        cancelled: true,\n      }));\n      const effects: Effect[] = [...drainEffects];\n      const active = activeTurnFromPhase(s.phase);\n      let newCommittedTurns = s.committedTurns;\n      if (active) {\n        const errorTurn: AcpTurn = {\n          ...active,\n          status: 'error',\n          endSeq: s.nextSeq,\n          stopReason: null,\n        };\n        newCommittedTurns = [...s.committedTurns, errorTurn];\n        effects.push({ type: 'turnCommitted', turn: errorTurn });\n      }\n      effects.push({ type: 'state' }, { type: 'closed', exitCode: ev.exitCode });\n      return {\n        state: {\n          ...s,\n          phase: { kind: 'closed', exitCode: ev.exitCode },\n          committedTurns: newCommittedTurns,\n          pendingPermissions: [],\n        },\n        effects,\n      };\n    }\n  }\n}\n\n// ---------------------------------------------------------------------------\n// Internal helpers\n// ---------------------------------------------------------------------------\n\nfunction warn(\n  s: SessionMachineState,\n  message: string\n): { state: SessionMachineState; effects: Effect[] } {\n  return { state: s, effects: [{ type: 'warn', message }] };\n}\n\nfunction makeTurn(s: SessionMachineState, source: TurnSource): AcpTurn {\n  return {\n    id: `turn-${s.conversationId}-${s.nextTurnIndex}`,\n    status: 'active',\n    source,\n    startSeq: s.nextSeq,\n    endSeq: null,\n    stopReason: null,\n    updates: [],\n  };\n}\n\nfunction replaceTurnInPhase(phase: SessionPhase, turn: AcpTurn): SessionPhase {\n  switch (phase.kind) {\n    case 'replaying':\n      return { kind: 'replaying', turn };\n    case 'working':\n      return { kind: 'working', turn };\n    case 'cancelling':\n      return { kind: 'cancelling', turn };\n    default:\n      return phase;\n  }\n}\n\n/**\n * Returns true if the incoming session setup event carries metadata that differs\n * from what the machine already has. Used to decide whether to emit a `meta`\n * effect alongside the `state` effect.\n */\nfunction needsMetaEffect(\n  s: SessionMachineState,\n  ev: { modes?: SessionModeState | null; configOptions?: readonly SessionConfigOption[] | null }\n): boolean {\n  return ev.modes !== undefined || ev.configOptions !== undefined;\n}\n\n// ---------------------------------------------------------------------------\n// isPromptReady — shared predicate (no longer from affordances.ts)\n// ---------------------------------------------------------------------------\n\n/**\n * Returns true when the lifecycle allows sending a prompt.\n * Shared between the state machine `decide` logic and the UI affordance layer.\n */\nexport function isPromptReady(lifecycle: SessionLifecycle): boolean {\n  return lifecycle === 'ready';\n}\n\n// ---------------------------------------------------------------------------\n// SessionMachine — stateful wrapper around the pure decide/evolve functions\n// ---------------------------------------------------------------------------\n\n/**\n * Stateful wrapper around `decide` and `evolve`. Holds one `SessionMachineState`\n * and exposes a command/event API that returns Effects for the runtime (or the\n * renderer) to interpret. Performs no I/O.\n */\nexport class SessionMachine {\n  private _state: SessionMachineState;\n\n  constructor(conversationId: string) {\n    this._state = initialMachineState(conversationId);\n  }\n\n  // --- Raw state passthrough (runtime needs direct access) ---\n\n  get phase(): SessionPhase {\n    return this._state.phase;\n  }\n  get lifecycle(): SessionLifecycle {\n    return phaseToLifecycle(this._state.phase);\n  }\n  get pendingPermissions(): readonly AcpPermissionRequest[] {\n    return this._state.pendingPermissions;\n  }\n  get modes(): SessionModeState | null {\n    return this._state.modes;\n  }\n  get nextTurnIndex(): number {\n    return this._state.nextTurnIndex;\n  }\n  get committedTurns(): readonly AcpTurn[] {\n    return this._state.committedTurns;\n  }\n  get lastStopReason(): StopReason | null {\n    return this._state.lastStopReason;\n  }\n\n  // --- UI affordance getters ---\n\n  /** True while the agent is actively working or acknowledging a cancel. */\n  get isWorking(): boolean {\n    return this._state.phase.kind === 'working' || this._state.phase.kind === 'cancelling';\n  }\n\n  /** True in any transient state where the agent is not idle or ready. */\n  get isBusy(): boolean {\n    const k = this._state.phase.kind;\n    return k === 'starting' || k === 'replaying' || k === 'working' || k === 'cancelling';\n  }\n\n  /** True when at least one permission request is awaiting a user decision. */\n  get hasPendingPermission(): boolean {\n    return this._state.pendingPermissions.length > 0;\n  }\n\n  /** True when the user may submit a new prompt (ready and no pending permission). */\n  get canSubmit(): boolean {\n    return isPromptReady(this.lifecycle) && !this.hasPendingPermission;\n  }\n\n  /** True when the user may cancel the current turn. */\n  get canCancel(): boolean {\n    return this._state.phase.kind === 'working';\n  }\n\n  // --- Command / event API ---\n\n  /**\n   * Validate a command, apply the resulting events, and return all effects.\n   * Returns an Err if the command is rejected; no state change occurs on rejection.\n   */\n  dispatch(cmd: Command): Result<Effect[], AcpRuntimeError> {\n    const decision = decide(this._state, cmd);\n    if (!decision.success) return decision;\n    const allEffects: Effect[] = [];\n    for (const event of decision.data) {\n      const { state, effects } = evolve(this._state, event);\n      this._state = state;\n      allEffects.push(...effects);\n    }\n    return ok(allEffects);\n  }\n\n  /**\n   * Unconditionally fold one or more domain events and return all effects.\n   * Out-of-place events yield only a diagnostic `warn` effect.\n   */\n  apply(...events: DomainEvent[]): Effect[] {\n    const allEffects: Effect[] = [];\n    for (const event of events) {\n      const { state, effects } = evolve(this._state, event);\n      this._state = state;\n      allEffects.push(...effects);\n    }\n    return allEffects;\n  }\n\n  /**\n   * Reconstruct session-level state from a `SessionSnapshot` received over IPC.\n   * The renderer uses this to mirror the runtime's state without re-running the\n   * full event stream. The `committedTurns` and seq counters are left untouched —\n   * the FE tracks the transcript separately via the turn-update channel.\n   */\n  applySnapshot(s: SessionSnapshot): void {\n    const activeTurnId = s.activeTurnId;\n    let phase: SessionPhase;\n    switch (s.lifecycle) {\n      case 'starting':\n        phase = { kind: 'starting' };\n        break;\n      case 'replaying':\n        phase = {\n          kind: 'replaying',\n          turn: activeTurnId ? placeholderTurn(activeTurnId) : placeholderTurn('replay'),\n        };\n        break;\n      case 'working':\n        phase = {\n          kind: 'working',\n          turn: activeTurnId ? placeholderTurn(activeTurnId) : placeholderTurn('working'),\n        };\n        break;\n      case 'cancelling':\n        phase = {\n          kind: 'cancelling',\n          turn: activeTurnId ? placeholderTurn(activeTurnId) : placeholderTurn('cancelling'),\n        };\n        break;\n      case 'ready':\n        phase = { kind: 'ready' };\n        break;\n      case 'closed':\n        phase = { kind: 'closed', exitCode: null };\n        break;\n    }\n    this._state = {\n      ...this._state,\n      phase,\n      pendingPermissions: s.pendingPermissions,\n      modes: s.modes,\n      configOptions: s.configOptions,\n      availableCommands: s.availableCommands,\n      lastStopReason: s.lastStopReason,\n      usage: s.usage,\n    };\n  }\n\n  // --- Delegation helpers matching the runtime's public API ---\n\n  /** Returns the full session state (mirrors getSessionState on the runtime). */\n  sessionState(): SessionState {\n    const activeTurn = activeTurnFromPhase(this._state.phase);\n    return {\n      lifecycle: this.lifecycle,\n      activeTurn: activeTurn ? structuredClone(activeTurn) : null,\n      pendingPermissions: structuredClone([...this._state.pendingPermissions]),\n      modes: this._state.modes ? structuredClone(this._state.modes) : null,\n      configOptions: structuredClone([...this._state.configOptions]),\n      availableCommands: structuredClone([...this._state.availableCommands]),\n      lastStopReason: this._state.lastStopReason,\n      usage: this._state.usage ? structuredClone(this._state.usage) : null,\n    };\n  }\n\n  /** Returns the committed chat history (mirrors getChatHistory on the runtime). */\n  chatHistory(): ChatHistory {\n    return {\n      turns: this._state.committedTurns.map((t) => structuredClone(t)),\n      complete: this._state.phase.kind !== 'starting' && this._state.phase.kind !== 'replaying',\n    };\n  }\n}\n\n/** Create a lightweight placeholder turn for applySnapshot phase reconstruction. */\nfunction placeholderTurn(id: string): AcpTurn {\n  return {\n    id,\n    status: 'active',\n    source: 'live',\n    startSeq: 0,\n    endSeq: null,\n    stopReason: null,\n    updates: [],\n  };\n}\n",
packages/core/src/acp/acp-transcript-parser/fixtures/claude-acp-transcript.json:1728:                "text": "```\n1\t/**\n2\t * Pure ACP session state machine.\n3\t *\n4\t * Separates inputs into two distinct kinds:\n5\t *\n6\t * - Commands — intents from the public API that MAY be rejected by validation.\n7\t *   They produce zero or more DomainEvents on success, or an AcpRuntimeError on\n8\t *   failure. No state changes occur on rejection.\n9\t *\n10\t * - DomainEvents — facts from the agent process, ACP notifications, or our own\n11\t *   orchestration that are ALWAYS folded into state. An out-of-place event\n12\t *   yields only a diagnostic `warn` Effect, never an error.\n13\t *\n14\t * The two pure functions `decide` and `evolve` contain no I/O. The runtime\n15\t * feeds commands through `decide` to get events, then feeds events through\n16\t * `evolve` to get the next state and the list of Effects to perform.\n17\t *\n18\t * State machine transitions:\n19\t *\n20\t *   starting → replaying (E: ReplayStarted — only when loadSession capable)\n21\t *   starting → ready     (E: SessionReady — newSession path)\n22\t *   replaying → ready    (E: ReplayEnded)\n23\t *   ready → working      (C: Prompt → E: PromptStarted)\n24\t *   working → ready      (E: TurnEnded)\n25\t *   working → cancelling (C: Cancel → E: CancellationRequested)\n26\t *   cancelling → ready   (E: TurnEnded)\n27\t *   {ready,working,cancelling} → closed (E: ProcessClosed)\n28\t */\n29\t\n30\timport type {\n31\t  AvailableCommand,\n32\t  SessionConfigOption,\n33\t  SessionModeState,\n34\t  StopReason,\n35\t} from '@agentclientprotocol/sdk';\n36\timport type { Result } from '@emdash/shared';\n37\timport { ok } from '@emdash/shared';\n38\timport type { AgentUpdate } from './agent-update';\n39\timport type { AcpRuntimeError } from './errors';\n40\timport { acpErr } from './errors';\n41\timport type { AcpPermissionRequest } from './permissions';\n42\timport type {\n43\t  AcpTurn,\n44\t  ChatHistory,\n45\t  SessionSnapshot,\n46\t  SessionState,\n47\t  SessionUsage,\n48\t  TurnSource,\n49\t  TurnStatus,\n50\t} from './state';\n51\t\n52\t// Re-export the snapshot mirror primitives so renderer-safe consumers can import\n53\t// them from this node-free entry instead of the full `@emdash/core/acp` barrel.\n54\texport { toSessionSnapshot, type SessionSnapshot } from './state';\n55\t\n56\t// ---------------------------------------------------------------------------\n57\t// Phase (discriminated union carrying the active turn in-line)\n58\t// ---------------------------------------------------------------------------\n59\t\n60\texport type SessionPhase =\n61\t  | { kind: 'starting' }\n62\t  | { kind: 'replaying'; turn: AcpTurn }\n63\t  | { kind: 'ready' }\n64\t  | { kind: 'working'; turn: AcpTurn }\n65\t  | { kind: 'cancelling'; turn: AcpTurn }\n66\t  | { kind: 'closed'; exitCode: number | null };\n67\t\n68\t/** Derives the `SessionLifecycle` string from a phase. */\n69\texport function phaseToLifecycle(phase: SessionPhase): SessionLifecycle {\n70\t  return phase.kind;\n71\t}\n72\t\n73\t/** The active turn if the phase carries one, otherwise null. */\n74\texport function activeTurnFromPhase(phase: SessionPhase): AcpTurn | null {\n75\t  if (phase.kind === 'replaying' || phase.kind === 'working' || phase.kind === 'cancelling') {\n76\t    return phase.turn;\n77\t  }\n78\t  return null;\n79\t}\n80\t\n81\t// Re-export for consumers that only care about the lifecycle string\n82\texport type SessionLifecycle =\n83\t  | 'starting'\n84\t  | 'replaying'\n85\t  | 'ready'\n86\t  | 'working'\n87\t  | 'cancelling'\n88\t  | 'closed';\n89\t\n90\t// ---------------------------------------------------------------------------\n91\t// Machine state\n92\t// ---------------------------------------------------------------------------\n93\t\n94\texport interface SessionMachineState {\n95\t  readonly conversationId: string;\n96\t  readonly phase: SessionPhase;\n97\t  readonly committedTurns: readonly AcpTurn[];\n98\t  readonly pendingPermissions: readonly AcpPermissionRequest[];\n99\t  /**\n100\t   * Agent-advertised session modes. Null until the first newSession or\n101\t   * loadSession response arrives, or if the agent doesn't support modes.\n102\t   */\n103\t  readonly modes: SessionModeState | null;\n104\t  /**\n105\t   * Full set of session config options as reported by the agent. The model\n106\t   * selector is one of these (category === 'model'). Authoritative — updated\n107\t   * from newSession/loadSession responses, setSessionConfigOption responses,\n108\t   * and config_option_update notifications.\n109\t   */\n110\t  readonly configOptions: readonly SessionConfigOption[];\n111\t  /** Slash commands the agent currently supports. */\n112\t  readonly availableCommands: readonly AvailableCommand[];\n113\t  /**\n114\t   * The stop reason from the last completed turn. Null on first start or\n115\t   * if no turn has completed yet. Drives the composer's notice band.\n116\t   */\n117\t  readonly lastStopReason: StopReason | null;\n118\t  /** Latest context-window and cost figures from usage_update, null until the first notification. */\n119\t  readonly usage: SessionUsage | null;\n120\t  /** Monotonic sequence counter — shared across all turns of a conversation. */\n121\t  readonly nextSeq: number;\n122\t  /** Counter used to generate unique, stable turn ids. */\n123\t  readonly nextTurnIndex: number;\n124\t}\n125\t\n126\texport function initialMachineState(conversationId: string): SessionMachineState {\n127\t  return {\n128\t    conversationId,\n129\t    phase: { kind: 'starting' },\n130\t    committedTurns: [],\n131\t    pendingPermissions: [],\n132\t    modes: null,\n133\t    configOptions: [],\n134\t    availableCommands: [],\n135\t    lastStopReason: null,\n136\t    usage: null,\n137\t    nextSeq: 0,\n138\t    nextTurnIndex: 0,\n139\t  };\n140\t}\n141\t\n142\t// ---------------------------------------------------------------------------\n143\t// Commands (validated intents — may be rejected)\n144\t// ---------------------------------------------------------------------------\n145\t\n146\texport type Command =\n147\t  /** Send a user message to the agent. Only valid when phase === 'ready'. */\n148\t  | { type: 'Prompt'; userUpdate: AgentUpdate }\n149\t  /** Cancel the in-flight turn. Only valid when phase === 'working'. Idempotent elsewhere. */\n150\t  | { type: 'Cancel' }\n151\t  /**\n152\t   * Resolve a pending permission request. Only valid when the requestId is\n153\t   * present in pendingPermissions.\n154\t   */\n155\t  | { type: 'ResolvePermission'; requestId: string; optionId: string | null }\n156\t  /** Switch the active session mode. Only valid when modes is non-null and modeId is available. */\n157\t  | { type: 'SetMode'; modeId: string }\n158\t  /**\n159\t   * Change the active model (or any other config option by id). The runtime\n160\t   * sends this as setSessionConfigOption; the response is authoritative.\n161\t   */\n162\t  | { type: 'SetConfigOption'; configId: string; value: string };\n163\t\n164\t// ---------------------------------------------------------------------------\n165\t// Domain events (facts — always folded)\n166\t// ---------------------------------------------------------------------------\n167\t\n168\texport type DomainEvent =\n169\t  /** Session established via loadSession — replay turn begins. */\n170\t  | { type: 'ReplayStarted' }\n171\t  /** Replay turn finished. */\n172\t  | { type: 'ReplayEnded'; status: Exclude<TurnStatus, 'active'> }\n173\t  /** Session established via newSession — immediately ready. */\n174\t  | {\n175\t      type: 'SessionReady';\n176\t      modes?: SessionModeState | null;\n177\t      configOptions?: readonly SessionConfigOption[] | null;\n178\t    }\n179\t  /** Session loaded via loadSession — session is ready after replay. Carries session metadata. */\n180\t  | {\n181\t      type: 'SessionLoaded';\n182\t      modes?: SessionModeState | null;\n183\t      configOptions?: readonly SessionConfigOption[] | null;\n184\t    }\n185\t  /** A new live turn begins, opening the working phase. */\n186\t  | { type: 'PromptStarted'; userUpdate: AgentUpdate }\n187\t  /** A turn-level update arrived from the agent. */\n188\t  | { type: 'Updated'; update: AgentUpdate }\n189\t  /** The active turn ended. */\n190\t  | { type: 'TurnEnded'; outcome: TurnOutcome }\n191\t  /** User initiated cancellation — transition to cancelling. */\n192\t  | { type: 'CancellationRequested' }\n193\t  /** Agent requested user permission for a tool call. */\n194\t  | { type: 'PermissionRequested'; request: AcpPermissionRequest }\n195\t  /** A pending permission was resolved (by user or by drain). */\n196\t  | { type: 'PermissionResolved'; requestId: string }\n197\t  /** Session-scoped metadata changed (modes / configOptions / availableCommands / usage). */\n198\t  | {\n199\t      type: 'MetaChanged';\n200\t      modes?: SessionModeState | null;\n201\t      configOptions?: readonly SessionConfigOption[] | null;\n202\t      availableCommands?: readonly AvailableCommand[] | null;\n203\t      usage?: SessionUsage | null;\n204\t    }\n205\t  /** The agent process exited or the connection closed. */\n206\t  | { type: 'ProcessClosed'; exitCode: number | null };\n207\t\n208\texport type TurnOutcome = { kind: 'stopped'; stopReason: StopReason } | { kind: 'errored' };\n209\t\n210\t// ---------------------------------------------------------------------------\n211\t// Effects (outputs that the runtime interprets — no I/O inside the machine)\n212\t// ---------------------------------------------------------------------------\n213\t\n214\texport type Effect =\n215\t  /** Emit the current lifecycle + activeTurnId to the listener. */\n216\t  | { type: 'state' }\n217\t  /** Emit a turn update to the listener. */\n218\t  | { type: 'update'; turnId: string; seq: number; update: AgentUpdate }\n219\t  /** Commit the turn to history and notify the listener. */\n220\t  | { type: 'turnCommitted'; turn: AcpTurn }\n221\t  /** Notify the listener of a new permission request. */\n222\t  | { type: 'permissionRequest'; request: AcpPermissionRequest }\n223\t  /**\n224\t   * Notify the listener that a permission was resolved. Also answers the\n225\t   * non-serializable resolver callback held by the runtime.\n226\t   */\n227\t  | { type: 'permissionResolved'; requestId: string; cancelled: boolean }\n228\t  /** Notify the listener that session-scoped metadata changed. */\n229\t  | { type: 'meta' }\n230\t  /** Notify the listener that the session closed. */\n231\t  | { type: 'closed'; exitCode: number | null }\n232\t  /** Emit start/stop/error agent lifecycle events. */\n233\t  | { type: 'agentEvent'; phase: 'start' | 'stop' | 'error' }\n234\t  /** Log a diagnostic warning for unexpected but non-fatal situations. */\n235\t  | { type: 'warn'; message: string };\n236\t\n237\t// ---------------------------------------------------------------------------\n238\t// decide — pure validation, no state change\n239\t// ---------------------------------------------------------------------------\n240\t\n241\t/**\n242\t * Validates a command against the current state. Returns the list of\n243\t * DomainEvents to fold if valid, or an AcpRuntimeError if not.\n244\t */\n245\texport function decide(\n246\t  s: SessionMachineState,\n247\t  cmd: Command\n248\t): Result<DomainEvent[], AcpRuntimeError> {\n249\t  switch (cmd.type) {\n250\t    case 'Prompt': {\n251\t      if (!isPromptReady(phaseToLifecycle(s.phase))) {\n252\t        return acpErr.invalidState(`Cannot send a prompt while session is '${s.phase.kind}'`);\n253\t      }\n254\t      return ok([{ type: 'PromptStarted', userUpdate: cmd.userUpdate }]);\n255\t    }\n256\t\n257\t    case 'Cancel': {\n258\t      if (s.phase.kind !== 'working') {\n259\t        // Idempotent — cancelling or already ready/closed is fine\n260\t        return ok([]);\n261\t      }\n262\t      return ok([{ type: 'CancellationRequested' }]);\n263\t    }\n264\t\n265\t    case 'ResolvePermission': {\n266\t      const found = s.pendingPermissions.some((p) => p.requestId === cmd.requestId);\n267\t      if (!found) {\n268\t        return acpErr.invalidState(`No pending permission request with id '${cmd.requestId}'`);\n269\t      }\n270\t      return ok([{ type: 'PermissionResolved', requestId: cmd.requestId }]);\n271\t    }\n272\t\n273\t    case 'SetMode': {\n274\t      if (!s.modes) {\n275\t        return acpErr.invalidState('Agent does not support session modes');\n276\t      }\n277\t      const available = s.modes.availableModes.some((m) => m.id === cmd.modeId);\n278\t      if (!available) {\n279\t        return acpErr.setModeFailed({\n280\t          name: 'Error',\n281\t          message: `Mode '${cmd.modeId}' is not in the available modes list`,\n282\t        });\n283\t      }\n284\t      // The actual RPC call happens in the runtime; the machine only validates.\n285\t      // The MetaChanged event arrives after the RPC response and is the truth.\n286\t      return ok([]);\n287\t    }\n288\t\n289\t    case 'SetConfigOption': {\n290\t      // Validation: option must exist. The runtime sends the RPC and then\n291\t      // applies the returned configOptions via a MetaChanged event.\n292\t      const exists = s.configOptions.some((o) => o.id === cmd.configId);\n293\t      if (!exists) {\n294\t        return acpErr.setConfigFailed({\n295\t          name: 'Error',\n296\t          message: `Config option '${cmd.configId}' is not known`,\n297\t        });\n298\t      }\n299\t      return ok([]);\n300\t    }\n301\t  }\n302\t}\n303\t\n304\t// ---------------------------------------------------------------------------\n305\t// evolve — pure fold, no side effects\n306\t// ---------------------------------------------------------------------------\n307\t\n308\t/**\n309\t * Folds a DomainEvent into a new state, returning the updated state and the\n310\t * list of Effects that the runtime must perform (I/O, listener calls, etc.).\n311\t * An out-of-place event yields only a `warn` Effect and leaves state unchanged.\n312\t */\n313\texport function evolve(\n314\t  s: SessionMachineState,\n315\t  ev: DomainEvent\n316\t): { state: SessionMachineState; effects: Effect[] } {\n317\t  switch (ev.type) {\n318\t    case 'ReplayStarted': {\n319\t      if (s.phase.kind !== 'starting') {\n320\t        return warn(s, `ReplayStarted in phase '${s.phase.kind}'`);\n321\t      }\n322\t      const turn = makeTurn(s, 'replay');\n323\t      return {\n324\t        state: {\n325\t          ...s,\n326\t          phase: { kind: 'replaying', turn },\n327\t          nextTurnIndex: s.nextTurnIndex + 1,\n328\t        },\n329\t        effects: [{ type: 'state' }],\n330\t      };\n331\t    }\n332\t\n333\t    case 'ReplayEnded': {\n334\t      if (s.phase.kind !== 'replaying') {\n335\t        return warn(s, `ReplayEnded in phase '${s.phase.kind}'`);\n336\t      }\n337\t      const turn = s.phase.turn;\n338\t      const committed: AcpTurn = {\n339\t        ...turn,\n340\t        status: ev.status,\n341\t        endSeq: s.nextSeq,\n342\t        stopReason: null,\n343\t      };\n344\t      return {\n345\t        state: {\n346\t          ...s,\n347\t          phase: { kind: 'ready' },\n348\t          committedTurns: [...s.committedTurns, committed],\n349\t        },\n350\t        effects: [{ type: 'turnCommitted', turn: committed }, { type: 'state' }],\n351\t      };\n352\t    }\n353\t\n354\t    case 'SessionReady': {\n355\t      if (s.phase.kind !== 'starting') {\n356\t        return warn(s, `SessionReady in phase '${s.phase.kind}'`);\n357\t      }\n358\t      return {\n359\t        state: {\n360\t          ...s,\n361\t          phase: { kind: 'ready' },\n362\t          modes: ev.modes ?? s.modes,\n363\t          configOptions: ev.configOptions ?? s.configOptions,\n364\t        },\n365\t        effects: [\n366\t          { type: 'state' },\n367\t          ...(needsMetaEffect(s, ev) ? ([{ type: 'meta' }] as Effect[]) : []),\n368\t        ],\n369\t      };\n370\t    }\n371\t\n372\t    case 'SessionLoaded': {\n373\t      if (s.phase.kind !== 'replaying') {\n374\t        return warn(s, `SessionLoaded in phase '${s.phase.kind}'`);\n375\t      }\n376\t      return {\n377\t        state: {\n378\t          ...s,\n379\t          modes: ev.modes ?? s.modes,\n380\t          configOptions: ev.configOptions ?? s.configOptions,\n381\t        },\n382\t        effects: needsMetaEffect(s, ev) ? [{ type: 'meta' }] : [],\n383\t      };\n384\t    }\n385\t\n386\t    case 'PromptStarted': {\n387\t      if (s.phase.kind !== 'ready') {\n388\t        return warn(s, `PromptStarted in phase '${s.phase.kind}'`);\n389\t      }\n390\t      const turn = makeTurn(s, 'live');\n391\t      const seq = s.nextSeq;\n392\t      // Record the synthesized user message as the leading update\n393\t      const turnWithUser: AcpTurn = {\n394\t        ...turn,\n395\t        updates: [{ seq, update: ev.userUpdate }],\n396\t      };\n397\t      return {\n398\t        state: {\n399\t          ...s,\n400\t          phase: { kind: 'working', turn: turnWithUser },\n401\t          nextSeq: seq + 1,\n402\t          nextTurnIndex: s.nextTurnIndex + 1,\n403\t        },\n404\t        effects: [\n405\t          { type: 'state' },\n406\t          { type: 'update', turnId: turn.id, seq, update: ev.userUpdate },\n407\t          { type: 'agentEvent', phase: 'start' },\n408\t        ],\n409\t      };\n410\t    }\n411\t\n412\t    case 'Updated': {\n413\t      const active = activeTurnFromPhase(s.phase);\n414\t      if (!active) {\n415\t        return warn(s, `Updated with no active turn (phase: '${s.phase.kind}')`);\n416\t      }\n417\t      const seq = s.nextSeq;\n418\t      const updatedTurn: AcpTurn = {\n419\t        ...active,\n420\t        updates: [...active.updates, { seq, update: ev.update }],\n421\t      };\n422\t      return {\n423\t        state: {\n424\t          ...s,\n425\t          phase: replaceTurnInPhase(s.phase, updatedTurn),\n426\t          nextSeq: seq + 1,\n427\t        },\n428\t        effects: [{ type: 'update', turnId: active.id, seq, update: ev.update }],\n429\t        // NB: lifecycle deliberately unchanged — Updated never flips to 'working'\n430\t      };\n431\t    }\n432\t\n433\t    case 'TurnEnded': {\n434\t      const active = activeTurnFromPhase(s.phase);\n435\t      if (!active) {\n436\t        return warn(s, `TurnEnded with no active turn (phase: '${s.phase.kind}')`);\n437\t      }\n438\t      const stopReason = ev.outcome.kind === 'stopped' ? ev.outcome.stopReason : null;\n439\t      const status: Exclude<TurnStatus, 'active'> =\n440\t        ev.outcome.kind === 'errored'\n441\t          ? 'error'\n442\t          : stopReason === 'cancelled'\n443\t            ? 'cancelled'\n444\t            : 'complete';\n445\t      const committed: AcpTurn = {\n446\t        ...active,\n447\t        status,\n448\t        endSeq: s.nextSeq,\n449\t        stopReason,\n450\t      };\n451\t      return {\n452\t        state: {\n453\t          ...s,\n454\t          phase: { kind: 'ready' },\n455\t          committedTurns: [...s.committedTurns, committed],\n456\t          lastStopReason: stopReason,\n457\t        },\n458\t        effects: [\n459\t          { type: 'turnCommitted', turn: committed },\n460\t          { type: 'state' },\n461\t          { type: 'agentEvent', phase: ev.outcome.kind === 'errored' ? 'error' : 'stop' },\n462\t        ],\n463\t      };\n464\t    }\n465\t\n466\t    case 'CancellationRequested': {\n467\t      if (s.phase.kind !== 'working') {\n468\t        return warn(s, `CancellationRequested in phase '${s.phase.kind}'`);\n469\t      }\n470\t      // Drain all pending permissions with cancelled=true\n471\t      const drainEffects: Effect[] = s.pendingPermissions.map((p) => ({\n472\t        type: 'permissionResolved' as const,\n473\t        requestId: p.requestId,\n474\t        cancelled: true,\n475\t      }));\n476\t      return {\n477\t        state: {\n478\t          ...s,\n479\t          phase: { kind: 'cancelling', turn: s.phase.turn },\n480\t          pendingPermissions: [],\n481\t        },\n482\t        effects: [...drainEffects, { type: 'state' }],\n483\t      };\n484\t    }\n485\t\n486\t    case 'PermissionRequested': {\n487\t      return {\n488\t        state: {\n489\t          ...s,\n490\t          pendingPermissions: [...s.pendingPermissions, ev.request],\n491\t        },\n492\t        effects: [{ type: 'permissionRequest', request: ev.request }],\n493\t      };\n494\t    }\n495\t\n496\t    case 'PermissionResolved': {\n497\t      return {\n498\t        state: {\n499\t          ...s,\n500\t          pendingPermissions: s.pendingPermissions.filter((p) => p.requestId !== ev.requestId),\n501\t        },\n502\t        effects: [{ type: 'permissionResolved', requestId: ev.requestId, cancelled: false }],\n503\t      };\n504\t    }\n505\t\n506\t    case 'MetaChanged': {\n507\t      return {\n508\t        state: {\n509\t          ...s,\n510\t          modes: ev.modes !== undefined ? (ev.modes ?? s.modes) : s.modes,\n511\t          configOptions:\n512\t            ev.configOptions !== undefined\n513\t              ? (ev.configOptions ?? s.configOptions)\n514\t              : s.configOptions,\n515\t          availableCommands:\n516\t            ev.availableCommands !== undefined\n517\t              ? (ev.availableCommands ?? s.availableCommands)\n518\t              : s.availableCommands,\n519\t          usage: ev.usage !== undefined ? (ev.usage ?? s.usage) : s.usage,\n520\t        },\n521\t        effects: [{ type: 'meta' }],\n522\t      };\n523\t    }\n524\t\n525\t    case 'ProcessClosed': {\n526\t      const drainEffects: Effect[] = s.pendingPermissions.map((p) => ({\n527\t        type: 'permissionResolved' as const,\n528\t        requestId: p.requestId,\n529\t        cancelled: true,\n530\t      }));\n531\t      const effects: Effect[] = [...drainEffects];\n532\t      const active = activeTurnFromPhase(s.phase);\n533\t      let newCommittedTurns = s.committedTurns;\n534\t      if (active) {\n535\t        const errorTurn: AcpTurn = {\n536\t          ...active,\n537\t          status: 'error',\n538\t          endSeq: s.nextSeq,\n539\t          stopReason: null,\n540\t        };\n541\t        newCommittedTurns = [...s.committedTurns, errorTurn];\n542\t        effects.push({ type: 'turnCommitted', turn: errorTurn });\n543\t      }\n544\t      effects.push({ type: 'state' }, { type: 'closed', exitCode: ev.exitCode });\n545\t      return {\n546\t        state: {\n547\t          ...s,\n548\t          phase: { kind: 'closed', exitCode: ev.exitCode },\n549\t          committedTurns: newCommittedTurns,\n550\t          pendingPermissions: [],\n551\t        },\n552\t        effects,\n553\t      };\n554\t    }\n555\t  }\n556\t}\n557\t\n558\t// ---------------------------------------------------------------------------\n559\t// Internal helpers\n560\t// ---------------------------------------------------------------------------\n561\t\n562\tfunction warn(\n563\t  s: SessionMachineState,\n564\t  message: string\n565\t): { state: SessionMachineState; effects: Effect[] } {\n566\t  return { state: s, effects: [{ type: 'warn', message }] };\n567\t}\n568\t\n569\tfunction makeTurn(s: SessionMachineState, source: TurnSource): AcpTurn {\n570\t  return {\n571\t    id: `turn-${s.conversationId}-${s.nextTurnIndex}`,\n572\t    status: 'active',\n573\t    source,\n574\t    startSeq: s.nextSeq,\n575\t    endSeq: null,\n576\t    stopReason: null,\n577\t    updates: [],\n578\t  };\n579\t}\n580\t\n581\tfunction replaceTurnInPhase(phase: SessionPhase, turn: AcpTurn): SessionPhase {\n582\t  switch (phase.kind) {\n583\t    case 'replaying':\n584\t      return { kind: 'replaying', turn };\n585\t    case 'working':\n586\t      return { kind: 'working', turn };\n587\t    case 'cancelling':\n588\t      return { kind: 'cancelling', turn };\n589\t    default:\n590\t      return phase;\n591\t  }\n592\t}\n593\t\n594\t/**\n595\t * Returns true if the incoming session setup event carries metadata that differs\n596\t * from what the machine already has. Used to decide whether to emit a `meta`\n597\t * effect alongside the `state` effect.\n598\t */\n599\tfunction needsMetaEffect(\n600\t  s: SessionMachineState,\n601\t  ev: { modes?: SessionModeState | null; configOptions?: readonly SessionConfigOption[] | null }\n602\t): boolean {\n603\t  return ev.modes !== undefined || ev.configOptions !== undefined;\n604\t}\n605\t\n606\t// ---------------------------------------------------------------------------\n607\t// isPromptReady — shared predicate (no longer from affordances.ts)\n608\t// ---------------------------------------------------------------------------\n609\t\n610\t/**\n611\t * Returns true when the lifecycle allows sending a prompt.\n612\t * Shared between the state machine `decide` logic and the UI affordance layer.\n613\t */\n614\texport function isPromptReady(lifecycle: SessionLifecycle): boolean {\n615\t  return lifecycle === 'ready';\n616\t}\n617\t\n618\t// ---------------------------------------------------------------------------\n619\t// SessionMachine — stateful wrapper around the pure decide/evolve functions\n620\t// ---------------------------------------------------------------------------\n621\t\n622\t/**\n623\t * Stateful wrapper around `decide` and `evolve`. Holds one `SessionMachineState`\n624\t * and exposes a command/event API that returns Effects for the runtime (or the\n625\t * renderer) to interpret. Performs no I/O.\n626\t */\n627\texport class SessionMachine {\n628\t  private _state: SessionMachineState;\n629\t\n630\t  constructor(conversationId: string) {\n631\t    this._state = initialMachineState(conversationId);\n632\t  }\n633\t\n634\t  // --- Raw state passthrough (runtime needs direct access) ---\n635\t\n636\t  get phase(): SessionPhase {\n637\t    return this._state.phase;\n638\t  }\n639\t  get lifecycle(): SessionLifecycle {\n640\t    return phaseToLifecycle(this._state.phase);\n641\t  }\n642\t  get pendingPermissions(): readonly AcpPermissionRequest[] {\n643\t    return this._state.pendingPermissions;\n644\t  }\n645\t  get modes(): SessionModeState | null {\n646\t    return this._state.modes;\n647\t  }\n648\t  get nextTurnIndex(): number {\n649\t    return this._state.nextTurnIndex;\n650\t  }\n651\t  get committedTurns(): readonly AcpTurn[] {\n652\t    return this._state.committedTurns;\n653\t  }\n654\t  get lastStopReason(): StopReason | null {\n655\t    return this._state.lastStopReason;\n656\t  }\n657\t\n658\t  // --- UI affordance getters ---\n659\t\n660\t  /** True while the agent is actively working or acknowledging a cancel. */\n661\t  get isWorking(): boolean {\n662\t    return this._state.phase.kind === 'working' || this._state.phase.kind === 'cancelling';\n663\t  }\n664\t\n665\t  /** True in any transient state where the agent is not idle or ready. */\n666\t  get isBusy(): boolean {\n667\t    const k = this._state.phase.kind;\n668\t    return k === 'starting' || k === 'replaying' || k === 'working' || k === 'cancelling';\n669\t  }\n670\t\n671\t  /** True when at least one permission request is awaiting a user decision. */\n672\t  get hasPendingPermission(): boolean {\n673\t    return this._state.pendingPermissions.length > 0;\n674\t  }\n675\t\n676\t  /** True when the user may submit a new prompt (ready and no pending permission). */\n677\t  get canSubmit(): boolean {\n678\t    return isPromptReady(this.lifecycle) && !this.hasPendingPermission;\n679\t  }\n680\t\n681\t  /** True when the user may cancel the current turn. */\n682\t  get canCancel(): boolean {\n683\t    return this._state.phase.kind === 'working';\n684\t  }\n685\t\n686\t  // --- Command / event API ---\n687\t\n688\t  /**\n689\t   * Validate a command, apply the resulting events, and return all effects.\n690\t   * Returns an Err if the command is rejected; no state change occurs on rejection.\n691\t   */\n692\t  dispatch(cmd: Command): Result<Effect[], AcpRuntimeError> {\n693\t    const decision = decide(this._state, cmd);\n694\t    if (!decision.success) return decision;\n695\t    const allEffects: Effect[] = [];\n696\t    for (const event of decision.data) {\n697\t      const { state, effects } = evolve(this._state, event);\n698\t      this._state = state;\n699\t      allEffects.push(...effects);\n700\t    }\n701\t    return ok(allEffects);\n702\t  }\n703\t\n704\t  /**\n705\t   * Unconditionally fold one or more domain events and return all effects.\n706\t   * Out-of-place events yield only a diagnostic `warn` effect.\n707\t   */\n708\t  apply(...events: DomainEvent[]): Effect[] {\n709\t    const allEffects: Effect[] = [];\n710\t    for (const event of events) {\n711\t      const { state, effects } = evolve(this._state, event);\n712\t      this._state = state;\n713\t      allEffects.push(...effects);\n714\t    }\n715\t    return allEffects;\n716\t  }\n717\t\n718\t  /**\n719\t   * Reconstruct session-level state from a `SessionSnapshot` received over IPC.\n720\t   * The renderer uses this to mirror the runtime's state without re-running the\n721\t   * full event stream. The `committedTurns` and seq counters are left untouched —\n722\t   * the FE tracks the transcript separately via the turn-update channel.\n723\t   */\n724\t  applySnapshot(s: SessionSnapshot): void {\n725\t    const activeTurnId = s.activeTurnId;\n726\t    let phase: SessionPhase;\n727\t    switch (s.lifecycle) {\n728\t      case 'starting':\n729\t        phase = { kind: 'starting' };\n730\t        break;\n731\t      case 'replaying':\n732\t        phase = {\n733\t          kind: 'replaying',\n734\t          turn: activeTurnId ? placeholderTurn(activeTurnId) : placeholderTurn('replay'),\n735\t        };\n736\t        break;\n737\t      case 'working':\n738\t        phase = {\n739\t          kind: 'working',\n740\t          turn: activeTurnId ? placeholderTurn(activeTurnId) : placeholderTurn('working'),\n741\t        };\n742\t        break;\n743\t      case 'cancelling':\n744\t        phase = {\n745\t          kind: 'cancelling',\n746\t          turn: activeTurnId ? placeholderTurn(activeTurnId) : placeholderTurn('cancelling'),\n747\t        };\n748\t        break;\n749\t      case 'ready':\n750\t        phase = { kind: 'ready' };\n751\t        break;\n752\t      case 'closed':\n753\t        phase = { kind: 'closed', exitCode: null };\n754\t        break;\n755\t    }\n756\t    this._state = {\n757\t      ...this._state,\n758\t      phase,\n759\t      pendingPermissions: s.pendingPermissions,\n760\t      modes: s.modes,\n761\t      configOptions: s.configOptions,\n762\t      availableCommands: s.availableCommands,\n763\t      lastStopReason: s.lastStopReason,\n764\t      usage: s.usage,\n765\t    };\n766\t  }\n767\t\n768\t  // --- Delegation helpers matching the runtime's public API ---\n769\t\n770\t  /** Returns the full session state (mirrors getSessionState on the runtime). */\n771\t  sessionState(): SessionState {\n772\t    const activeTurn = activeTurnFromPhase(this._state.phase);\n773\t    return {\n774\t      lifecycle: this.lifecycle,\n775\t      activeTurn: activeTurn ? structuredClone(activeTurn) : null,\n776\t      pendingPermissions: structuredClone([...this._state.pendingPermissions]),\n777\t      modes: this._state.modes ? structuredClone(this._state.modes) : null,\n778\t      configOptions: structuredClone([...this._state.configOptions]),\n779\t      availableCommands: structuredClone([...this._state.availableCommands]),\n780\t      lastStopReason: this._state.lastStopReason,\n781\t      usage: this._state.usage ? structuredClone(this._state.usage) : null,\n782\t    };\n783\t  }\n784\t\n785\t  /** Returns the committed chat history (mirrors getChatHistory on the runtime). */\n786\t  chatHistory(): ChatHistory {\n787\t    return {\n788\t      turns: this._state.committedTurns.map((t) => structuredClone(t)),\n789\t      complete: this._state.phase.kind !== 'starting' && this._state.phase.kind !== 'replaying',\n790\t    };\n791\t  }\n792\t}\n793\t\n794\t/** Create a lightweight placeholder turn for applySnapshot phase reconstruction. */\n795\tfunction placeholderTurn(id: string): AcpTurn {\n796\t  return {\n797\t    id,\n798\t    status: 'active',\n799\t    source: 'live',\n800\t    startSeq: 0,\n801\t    endSeq: null,\n802\t    stopReason: null,\n803\t    updates: [],\n804\t  };\n805\t}\n806\t\n```",
packages/core/src/acp/acp-transcript-parser/fixtures/claude-acp-transcript.json:1734:          "rawOutput": "1\t/**\n2\t * Pure ACP session state machine.\n3\t *\n4\t * Separates inputs into two distinct kinds:\n5\t *\n6\t * - Commands — intents from the public API that MAY be rejected by validation.\n7\t *   They produce zero or more DomainEvents on success, or an AcpRuntimeError on\n8\t *   failure. No state changes occur on rejection.\n9\t *\n10\t * - DomainEvents — facts from the agent process, ACP notifications, or our own\n11\t *   orchestration that are ALWAYS folded into state. An out-of-place event\n12\t *   yields only a diagnostic `warn` Effect, never an error.\n13\t *\n14\t * The two pure functions `decide` and `evolve` contain no I/O. The runtime\n15\t * feeds commands through `decide` to get events, then feeds events through\n16\t * `evolve` to get the next state and the list of Effects to perform.\n17\t *\n18\t * State machine transitions:\n19\t *\n20\t *   starting → replaying (E: ReplayStarted — only when loadSession capable)\n21\t *   starting → ready     (E: SessionReady — newSession path)\n22\t *   replaying → ready    (E: ReplayEnded)\n23\t *   ready → working      (C: Prompt → E: PromptStarted)\n24\t *   working → ready      (E: TurnEnded)\n25\t *   working → cancelling (C: Cancel → E: CancellationRequested)\n26\t *   cancelling → ready   (E: TurnEnded)\n27\t *   {ready,working,cancelling} → closed (E: ProcessClosed)\n28\t */\n29\t\n30\timport type {\n31\t  AvailableCommand,\n32\t  SessionConfigOption,\n33\t  SessionModeState,\n34\t  StopReason,\n35\t} from '@agentclientprotocol/sdk';\n36\timport type { Result } from '@emdash/shared';\n37\timport { ok } from '@emdash/shared';\n38\timport type { AgentUpdate } from './agent-update';\n39\timport type { AcpRuntimeError } from './errors';\n40\timport { acpErr } from './errors';\n41\timport type { AcpPermissionRequest } from './permissions';\n42\timport type {\n43\t  AcpTurn,\n44\t  ChatHistory,\n45\t  SessionSnapshot,\n46\t  SessionState,\n47\t  SessionUsage,\n48\t  TurnSource,\n49\t  TurnStatus,\n50\t} from './state';\n51\t\n52\t// Re-export the snapshot mirror primitives so renderer-safe consumers can import\n53\t// them from this node-free entry instead of the full `@emdash/core/acp` barrel.\n54\texport { toSessionSnapshot, type SessionSnapshot } from './state';\n55\t\n56\t// ---------------------------------------------------------------------------\n57\t// Phase (discriminated union carrying the active turn in-line)\n58\t// ---------------------------------------------------------------------------\n59\t\n60\texport type SessionPhase =\n61\t  | { kind: 'starting' }\n62\t  | { kind: 'replaying'; turn: AcpTurn }\n63\t  | { kind: 'ready' }\n64\t  | { kind: 'working'; turn: AcpTurn }\n65\t  | { kind: 'cancelling'; turn: AcpTurn }\n66\t  | { kind: 'closed'; exitCode: number | null };\n67\t\n68\t/** Derives the `SessionLifecycle` string from a phase. */\n69\texport function phaseToLifecycle(phase: SessionPhase): SessionLifecycle {\n70\t  return phase.kind;\n71\t}\n72\t\n73\t/** The active turn if the phase carries one, otherwise null. */\n74\texport function activeTurnFromPhase(phase: SessionPhase): AcpTurn | null {\n75\t  if (phase.kind === 'replaying' || phase.kind === 'working' || phase.kind === 'cancelling') {\n76\t    return phase.turn;\n77\t  }\n78\t  return null;\n79\t}\n80\t\n81\t// Re-export for consumers that only care about the lifecycle string\n82\texport type SessionLifecycle =\n83\t  | 'starting'\n84\t  | 'replaying'\n85\t  | 'ready'\n86\t  | 'working'\n87\t  | 'cancelling'\n88\t  | 'closed';\n89\t\n90\t// ---------------------------------------------------------------------------\n91\t// Machine state\n92\t// ---------------------------------------------------------------------------\n93\t\n94\texport interface SessionMachineState {\n95\t  readonly conversationId: string;\n96\t  readonly phase: SessionPhase;\n97\t  readonly committedTurns: readonly AcpTurn[];\n98\t  readonly pendingPermissions: readonly AcpPermissionRequest[];\n99\t  /**\n100\t   * Agent-advertised session modes. Null until the first newSession or\n101\t   * loadSession response arrives, or if the agent doesn't support modes.\n102\t   */\n103\t  readonly modes: SessionModeState | null;\n104\t  /**\n105\t   * Full set of session config options as reported by the agent. The model\n106\t   * selector is one of these (category === 'model'). Authoritative — updated\n107\t   * from newSession/loadSession responses, setSessionConfigOption responses,\n108\t   * and config_option_update notifications.\n109\t   */\n110\t  readonly configOptions: readonly SessionConfigOption[];\n111\t  /** Slash commands the agent currently supports. */\n112\t  readonly availableCommands: readonly AvailableCommand[];\n113\t  /**\n114\t   * The stop reason from the last completed turn. Null on first start or\n115\t   * if no turn has completed yet. Drives the composer's notice band.\n116\t   */\n117\t  readonly lastStopReason: StopReason | null;\n118\t  /** Latest context-window and cost figures from usage_update, null until the first notification. */\n119\t  readonly usage: SessionUsage | null;\n120\t  /** Monotonic sequence counter — shared across all turns of a conversation. */\n121\t  readonly nextSeq: number;\n122\t  /** Counter used to generate unique, stable turn ids. */\n123\t  readonly nextTurnIndex: number;\n124\t}\n125\t\n126\texport function initialMachineState(conversationId: string): SessionMachineState {\n127\t  return {\n128\t    conversationId,\n129\t    phase: { kind: 'starting' },\n130\t    committedTurns: [],\n131\t    pendingPermissions: [],\n132\t    modes: null,\n133\t    configOptions: [],\n134\t    availableCommands: [],\n135\t    lastStopReason: null,\n136\t    usage: null,\n137\t    nextSeq: 0,\n138\t    nextTurnIndex: 0,\n139\t  };\n140\t}\n141\t\n142\t// ---------------------------------------------------------------------------\n143\t// Commands (validated intents — may be rejected)\n144\t// ---------------------------------------------------------------------------\n145\t\n146\texport type Command =\n147\t  /** Send a user message to the agent. Only valid when phase === 'ready'. */\n148\t  | { type: 'Prompt'; userUpdate: AgentUpdate }\n149\t  /** Cancel the in-flight turn. Only valid when phase === 'working'. Idempotent elsewhere. */\n150\t  | { type: 'Cancel' }\n151\t  /**\n152\t   * Resolve a pending permission request. Only valid when the requestId is\n153\t   * present in pendingPermissions.\n154\t   */\n155\t  | { type: 'ResolvePermission'; requestId: string; optionId: string | null }\n156\t  /** Switch the active session mode. Only valid when modes is non-null and modeId is available. */\n157\t  | { type: 'SetMode'; modeId: string }\n158\t  /**\n159\t   * Change the active model (or any other config option by id). The runtime\n160\t   * sends this as setSessionConfigOption; the response is authoritative.\n161\t   */\n162\t  | { type: 'SetConfigOption'; configId: string; value: string };\n163\t\n164\t// ---------------------------------------------------------------------------\n165\t// Domain events (facts — always folded)\n166\t// ---------------------------------------------------------------------------\n167\t\n168\texport type DomainEvent =\n169\t  /** Session established via loadSession — replay turn begins. */\n170\t  | { type: 'ReplayStarted' }\n171\t  /** Replay turn finished. */\n172\t  | { type: 'ReplayEnded'; status: Exclude<TurnStatus, 'active'> }\n173\t  /** Session established via newSession — immediately ready. */\n174\t  | {\n175\t      type: 'SessionReady';\n176\t      modes?: SessionModeState | null;\n177\t      configOptions?: readonly SessionConfigOption[] | null;\n178\t    }\n179\t  /** Session loaded via loadSession — session is ready after replay. Carries session metadata. */\n180\t  | {\n181\t      type: 'SessionLoaded';\n182\t      modes?: SessionModeState | null;\n183\t      configOptions?: readonly SessionConfigOption[] | null;\n184\t    }\n185\t  /** A new live turn begins, opening the working phase. */\n186\t  | { type: 'PromptStarted'; userUpdate: AgentUpdate }\n187\t  /** A turn-level update arrived from the agent. */\n188\t  | { type: 'Updated'; update: AgentUpdate }\n189\t  /** The active turn ended. */\n190\t  | { type: 'TurnEnded'; outcome: TurnOutcome }\n191\t  /** User initiated cancellation — transition to cancelling. */\n192\t  | { type: 'CancellationRequested' }\n193\t  /** Agent requested user permission for a tool call. */\n194\t  | { type: 'PermissionRequested'; request: AcpPermissionRequest }\n195\t  /** A pending permission was resolved (by user or by drain). */\n196\t  | { type: 'PermissionResolved'; requestId: string }\n197\t  /** Session-scoped metadata changed (modes / configOptions / availableCommands / usage). */\n198\t  | {\n199\t      type: 'MetaChanged';\n200\t      modes?: SessionModeState | null;\n201\t      configOptions?: readonly SessionConfigOption[] | null;\n202\t      availableCommands?: readonly AvailableCommand[] | null;\n203\t      usage?: SessionUsage | null;\n204\t    }\n205\t  /** The agent process exited or the connection closed. */\n206\t  | { type: 'ProcessClosed'; exitCode: number | null };\n207\t\n208\texport type TurnOutcome = { kind: 'stopped'; stopReason: StopReason } | { kind: 'errored' };\n209\t\n210\t// ---------------------------------------------------------------------------\n211\t// Effects (outputs that the runtime interprets — no I/O inside the machine)\n212\t// ---------------------------------------------------------------------------\n213\t\n214\texport type Effect =\n215\t  /** Emit the current lifecycle + activeTurnId to the listener. */\n216\t  | { type: 'state' }\n217\t  /** Emit a turn update to the listener. */\n218\t  | { type: 'update'; turnId: string; seq: number; update: AgentUpdate }\n219\t  /** Commit the turn to history and notify the listener. */\n220\t  | { type: 'turnCommitted'; turn: AcpTurn }\n221\t  /** Notify the listener of a new permission request. */\n222\t  | { type: 'permissionRequest'; request: AcpPermissionRequest }\n223\t  /**\n224\t   * Notify the listener that a permission was resolved. Also answers the\n225\t   * non-serializable resolver callback held by the runtime.\n226\t   */\n227\t  | { type: 'permissionResolved'; requestId: string; cancelled: boolean }\n228\t  /** Notify the listener that session-scoped metadata changed. */\n229\t  | { type: 'meta' }\n230\t  /** Notify the listener that the session closed. */\n231\t  | { type: 'closed'; exitCode: number | null }\n232\t  /** Emit start/stop/error agent lifecycle events. */\n233\t  | { type: 'agentEvent'; phase: 'start' | 'stop' | 'error' }\n234\t  /** Log a diagnostic warning for unexpected but non-fatal situations. */\n235\t  | { type: 'warn'; message: string };\n236\t\n237\t// ---------------------------------------------------------------------------\n238\t// decide — pure validation, no state change\n239\t// ---------------------------------------------------------------------------\n240\t\n241\t/**\n242\t * Validates a command against the current state. Returns the list of\n243\t * DomainEvents to fold if valid, or an AcpRuntimeError if not.\n244\t */\n245\texport function decide(\n246\t  s: SessionMachineState,\n247\t  cmd: Command\n248\t): Result<DomainEvent[], AcpRuntimeError> {\n249\t  switch (cmd.type) {\n250\t    case 'Prompt': {\n251\t      if (!isPromptReady(phaseToLifecycle(s.phase))) {\n252\t        return acpErr.invalidState(`Cannot send a prompt while session is '${s.phase.kind}'`);\n253\t      }\n254\t      return ok([{ type: 'PromptStarted', userUpdate: cmd.userUpdate }]);\n255\t    }\n256\t\n257\t    case 'Cancel': {\n258\t      if (s.phase.kind !== 'working') {\n259\t        // Idempotent — cancelling or already ready/closed is fine\n260\t        return ok([]);\n261\t      }\n262\t      return ok([{ type: 'CancellationRequested' }]);\n263\t    }\n264\t\n265\t    case 'ResolvePermission': {\n266\t      const found = s.pendingPermissions.some((p) => p.requestId === cmd.requestId);\n267\t      if (!found) {\n268\t        return acpErr.invalidState(`No pending permission request with id '${cmd.requestId}'`);\n269\t      }\n270\t      return ok([{ type: 'PermissionResolved', requestId: cmd.requestId }]);\n271\t    }\n272\t\n273\t    case 'SetMode': {\n274\t      if (!s.modes) {\n275\t        return acpErr.invalidState('Agent does not support session modes');\n276\t      }\n277\t      const available = s.modes.availableModes.some((m) => m.id === cmd.modeId);\n278\t      if (!available) {\n279\t        return acpErr.setModeFailed({\n280\t          name: 'Error',\n281\t          message: `Mode '${cmd.modeId}' is not in the available modes list`,\n282\t        });\n283\t      }\n284\t      // The actual RPC call happens in the runtime; the machine only validates.\n285\t      // The MetaChanged event arrives after the RPC response and is the truth.\n286\t      return ok([]);\n287\t    }\n288\t\n289\t    case 'SetConfigOption': {\n290\t      // Validation: option must exist. The runtime sends the RPC and then\n291\t      // applies the returned configOptions via a MetaChanged event.\n292\t      const exists = s.configOptions.some((o) => o.id === cmd.configId);\n293\t      if (!exists) {\n294\t        return acpErr.setConfigFailed({\n295\t          name: 'Error',\n296\t          message: `Config option '${cmd.configId}' is not known`,\n297\t        });\n298\t      }\n299\t      return ok([]);\n300\t    }\n301\t  }\n302\t}\n303\t\n304\t// ---------------------------------------------------------------------------\n305\t// evolve — pure fold, no side effects\n306\t// ---------------------------------------------------------------------------\n307\t\n308\t/**\n309\t * Folds a DomainEvent into a new state, returning the updated state and the\n310\t * list of Effects that the runtime must perform (I/