\t\n594\t/**\n595\t * Returns true if the incoming session setup event carries metadata that differs\n596\t * from what the machine already has. Used to decide whether to emit a `meta`\n597\t * effect alongside the `state` effect.\n598\t */\n599\tfunction needsMetaEffect(\n600\t  s: SessionMachineState,\n601\t  ev: { modes?: SessionModeState | null; configOptions?: readonly SessionConfigOption[] | null }\n602\t): boolean {\n603\t  return ev.modes !== undefined || ev.configOptions !== undefined;\n604\t}\n605\t\n606\t// ---------------------------------------------------------------------------\n607\t// isPromptReady — shared predicate (no longer from affordances.ts)\n608\t// ---------------------------------------------------------------------------\n609\t\n610\t/**\n611\t * Returns true when the lifecycle allows sending a prompt.\n612\t * Shared between the state machine `decide` logic and the UI affordance layer.\n613\t */\n614\texport function isPromptReady(lifecycle: SessionLifecycle): boolean {\n615\t  return lifecycle === 'ready';\n616\t}\n617\t\n618\t// ---------------------------------------------------------------------------\n619\t// SessionMachine — stateful wrapper around the pure decide/evolve functions\n620\t// ---------------------------------------------------------------------------\n621\t\n622\t/**\n623\t * Stateful wrapper around `decide` and `evolve`. Holds one `SessionMachineState`\n624\t * and exposes a command/event API that returns Effects for the runtime (or the\n625\t * renderer) to interpret. Performs no I/O.\n626\t */\n627\texport class SessionMachine {\n628\t  private _state: SessionMachineState;\n629\t\n630\t  constructor(conversationId: string) {\n631\t    this._state = initialMachineState(conversationId);\n632\t  }\n633\t\n634\t  // --- Raw state passthrough (runtime needs direct access) ---\n635\t\n636\t  get phase(): SessionPhase {\n637\t    return this._state.phase;\n638\t  }\n639\t  get lifecycle(): SessionLifecycle {\n640\t    ret