m './session-machine';\n\nconst CONV_ID = 'conv-test';\n\nfunction makeReady(): SessionMachineState {\n  const s0 = initialMachineState(CONV_ID);\n  const { state } = evolve(s0, { type: 'SessionReady' });\n  return state;\n}\n\nfunction makeWorking(): SessionMachineState {\n  const ready = makeReady();\n  const userUpdate: AgentUpdate = { kind: 'message', role: 'user', messageId: null, text: 'hello' };\n  const events = decide(ready, { type: 'Prompt', userUpdate });\n  if (!isOk(events)) throw new Error('decide Prompt failed');\n  let s = ready;\n  for (const ev of events.data) {\n    ({ state: s } = evolve(s, ev));\n\n===== acp-session-runtime.ts =====\nimport type {\n  Client,\n  CreateTerminalRequest,\n  CreateTerminalResponse,\n  KillTerminalRequest,\n  KillTerminalResponse,\n  LoadSessionRequest,\n  NewSessionRequest,\n  ReadTextFileRequest,\n  ReadTextFileResponse,\n  ReleaseTerminalRequest,\n  ReleaseTerminalResponse,\n  RequestPermissionRequest,\n  RequestPermissionResponse,\n  SessionNotification,\n  SessionUpdate,\n  SetSessionConfigOptionRequest,\n  SetSessionModeRequest,\n  TerminalOutputRequest,\n  TerminalOutputResponse,\n  WaitForTerminalExitRequest,\n  WaitForTerminalExitResponse,\n  WriteTextFileRequest,\n  WriteTextFileResponse,\n} from '@agentclientprotocol/sdk';\nimport type { Result } from '@emdash/shared';\nimport { isErr, LifecycleMap, ok, toSerializedError } from '@emdash/shared';\nimport type { AcpAgentApi, IAcpBehavior } from '../agents/plugins/capabilities/acp';\nimport { createAcpAgentConnection } from './acp-agent-connection';\nimport { AgentTerminalManager } from './agent-terminal-manager';\n\n===== session-machine.ts =====\n/**\n * Pure ACP session state machine.\n *\n * Separates inputs into two distinct kinds:\n *\n * - Commands — intents from the public API that MAY be rejected by validation.\n *   They produce zero or more DomainEvents on success, or an AcpRuntimeError on\n *   failure. No state changes occur on rejection.\n *\n * 